import{_ as t,o as a,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"The HTML <iframe> Element — Complete Attribute Reference","description":"","frontmatter":{},"headers":[],"relativePath":"html-iframe-element.md","filePath":"html-iframe-element.md","lastUpdated":1784187737000}'),d={name:"html-iframe-element.md"};function r(o,e,n,l,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="the-html-iframe-element-—-complete-attribute-reference" tabindex="-1">The HTML <code>&lt;iframe&gt;</code> Element — Complete Attribute Reference <a class="header-anchor" href="#the-html-iframe-element-—-complete-attribute-reference" aria-label="Permalink to &quot;The HTML `&lt;iframe&gt;` Element — Complete Attribute Reference&quot;">​</a></h1><p>This document explains the <strong>native HTML <code>&lt;iframe&gt;</code> element</strong> itself — every attribute it supports, what each one does, current browser status, and (where relevant) how it relates to this library&#39;s <code>&lt;IframeWrapper /&gt;</code> component. For the wrapper component&#39;s own props, see <a href="/api/parameters">Parameters</a> instead; this document is the lower-level reference those props are built on top of.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of contents&quot;">​</a></h2><ul><li><a href="#minimal-example">Minimal example</a></li><li><a href="#content-attributes">Content attributes</a> — <code>src</code>, <code>srcdoc</code></li><li><a href="#sandboxing">Sandboxing</a> — <code>sandbox</code> and every token it accepts</li><li><a href="#permissions">Permissions</a> — <code>allow</code>, and the deprecated <code>allowfullscreen</code> / <code>allowpaymentrequest</code></li><li><a href="#sizing--layout">Sizing &amp; layout</a> — <code>width</code>, <code>height</code>, and the deprecated <code>frameborder</code>/<code>scrolling</code>/<code>marginwidth</code>/<code>marginheight</code>/<code>align</code></li><li><a href="#loading-behavior">Loading behavior</a> — <code>loading</code></li><li><a href="#naming--targeting">Naming &amp; targeting</a> — <code>name</code></li><li><a href="#privacy">Privacy</a> — <code>referrerpolicy</code></li><li><a href="#accessibility">Accessibility</a> — <code>title</code></li><li><a href="#non-standard--experimental">Non-standard / experimental</a> — <code>csp</code></li><li><a href="#deprecated--obsolete-attributes">Deprecated / obsolete attributes</a></li><li><a href="#global-attributes-that-matter-in-practice">Global attributes that matter in practice</a></li><li><a href="#dom-properties--events-not-attributes-but-related">DOM properties &amp; events (not attributes, but related)</a></li><li><a href="#full-attribute-table">Full attribute table</a></li><li><a href="#mapping-to-iframewrapper-">Mapping to <code>&lt;IframeWrapper /&gt;</code></a></li></ul><hr><h2 id="minimal-example" tabindex="-1">Minimal example <a class="header-anchor" href="#minimal-example" aria-label="Permalink to &quot;Minimal example&quot;">​</a></h2><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/report.html&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Quarterly report preview&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allow-scripts allow-same-origin&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  loading</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lazy&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  referrerpolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;strict-origin-when-cross-origin&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;800&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;600&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Nearly every attribute below is optional; browsers render a functional (if under-specified) iframe with only <code>src</code> or <code>srcdoc</code> present. The example above reflects what a security- and accessibility-conscious usage looks like in practice.</p><hr><h2 id="content-attributes" tabindex="-1">Content attributes <a class="header-anchor" href="#content-attributes" aria-label="Permalink to &quot;Content attributes&quot;">​</a></h2><h3 id="src" tabindex="-1"><code>src</code> <a class="header-anchor" href="#src" aria-label="Permalink to &quot;`src`&quot;">​</a></h3><p>The URL of the document to embed. Can point to same-origin or cross-origin content — the browser enforces the same-origin policy on the result either way; <code>src</code> itself has no restriction on what URL you put there.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com/embed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="srcdoc" tabindex="-1"><code>srcdoc</code> <a class="header-anchor" href="#srcdoc" aria-label="Permalink to &quot;`srcdoc`&quot;">​</a></h3><p>Inline HTML to render inside the frame, as a string, instead of fetching a URL. When both <code>src</code> and <code>srcdoc</code> are present, conforming browsers use <code>srcdoc</code> and treat <code>src</code> as a fallback for browsers that don&#39;t support <code>srcdoc</code> (Internet Explorer and legacy Edge — not a practical concern in 2026, but the fallback behavior is still part of the spec).</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> srcdoc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">p&gt;Rendered inline, no request made.</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/p&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>A <code>srcdoc</code> document&#39;s origin is derived from the embedding document, so it is always same-origin with the page that contains the iframe (unless the iframe itself is sandboxed with <code>allow-same-origin</code> omitted, which forces an opaque/null origin instead).</p><hr><h2 id="sandboxing" tabindex="-1">Sandboxing <a class="header-anchor" href="#sandboxing" aria-label="Permalink to &quot;Sandboxing&quot;">​</a></h2><h3 id="sandbox" tabindex="-1"><code>sandbox</code> <a class="header-anchor" href="#sandbox" aria-label="Permalink to &quot;`sandbox`&quot;">​</a></h3><p>Applies extra restrictions to the embedded content. <strong>Absence of the attribute means no sandboxing at all</strong> — the iframe runs with the same privileges it would have as a top-level page. Presence of the attribute with an <strong>empty value</strong> (<code>sandbox=&quot;&quot;</code>) applies the maximum restriction set (scripts disabled, forms disabled, same-origin treated as a distinct opaque origin, etc.). Each token below re-enables one specific capability.</p><table tabindex="0"><thead><tr><th>Token</th><th>Re-enables</th></tr></thead><tbody><tr><td><code>allow-downloads</code></td><td>Downloading files, including via a <code>download</code> attribute on a link.</td></tr><tr><td><code>allow-forms</code></td><td>Form submission.</td></tr><tr><td><code>allow-modals</code></td><td><code>window.alert()</code>, <code>confirm()</code>, <code>prompt()</code>, and the <code>beforeunload</code> dialog.</td></tr><tr><td><code>allow-orientation-lock</code></td><td>The Screen Orientation API&#39;s <code>lock()</code> method.</td></tr><tr><td><code>allow-pointer-lock</code></td><td>The Pointer Lock API.</td></tr><tr><td><code>allow-popups</code></td><td><code>window.open()</code>, <code>target=&quot;_blank&quot;</code>, <code>showModalDialog()</code>.</td></tr><tr><td><code>allow-popups-to-escape-sandbox</code></td><td>Popups opened from the frame are <em>not</em> themselves sandboxed (without this, a popup inherits the opener&#39;s sandbox restrictions).</td></tr><tr><td><code>allow-presentation</code></td><td>Starting a presentation session (Presentation API).</td></tr><tr><td><code>allow-same-origin</code></td><td>Treats the content as being from its actual origin for same-origin-policy purposes, rather than forcing a unique opaque origin. <strong>Required for <code>contentDocument</code>/<code>contentWindow</code> access</strong> — this library&#39;s injection features depend on it.</td></tr><tr><td><code>allow-scripts</code></td><td>JavaScript execution inside the frame. Does <strong>not</strong> re-enable popups or automatic top-level navigation by itself.</td></tr><tr><td><code>allow-storage-access-by-user-activation</code></td><td>Calling <code>document.requestStorageAccess()</code> from within the frame.</td></tr><tr><td><code>allow-top-navigation</code></td><td>Navigating the <em>top-level</em> browsing context (not just itself).</td></tr><tr><td><code>allow-top-navigation-by-user-activation</code></td><td>Same as above, but only in response to a user gesture.</td></tr><tr><td><code>allow-top-navigation-to-custom-protocols</code></td><td>Top-level navigation to a non-<code>http(s)</code> URL scheme (e.g. <code>mailto:</code>, a custom app protocol).</td></tr></tbody></table><p><strong>The combination that matters most for this library:</strong><code>sandbox=&quot;allow-scripts allow-same-origin&quot;</code> — this is <code>&lt;IframeWrapper /&gt;</code>&#39;s default. It allows injected <code>js</code> to run and allows <code>getDocument()</code>/<code>getWindow()</code>/injection to work at all, since those require same-origin access. See <a href="/security">Security</a> for why this specific combination is appropriate for <em>content you control</em> but not for genuinely untrusted third-party HTML.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- Maximum restriction: scripts and forms disabled, forced opaque origin --&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sandbox</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/untrusted-preview.html&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- This library&#39;s default --&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allow-scripts allow-same-origin&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/report.html&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><h3 id="allow" tabindex="-1"><code>allow</code> <a class="header-anchor" href="#allow" aria-label="Permalink to &quot;`allow`&quot;">​</a></h3><p>A <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Guides/Permissions_Policy" target="_blank" rel="noreferrer">Permissions Policy</a> string controlling which browser features the embedded content may use — independent of <code>sandbox</code>, which governs document/scripting behavior rather than device/API access.</p><p>Common directives:</p><table tabindex="0"><thead><tr><th>Directive</th><th>Controls</th></tr></thead><tbody><tr><td><code>accelerometer</code></td><td>Access to accelerometer sensor data.</td></tr><tr><td><code>autoplay</code></td><td>Autoplaying media.</td></tr><tr><td><code>camera</code></td><td>Camera access (<code>getUserMedia</code>).</td></tr><tr><td><code>clipboard-write</code></td><td>Programmatic clipboard writes.</td></tr><tr><td><code>encrypted-media</code></td><td>Encrypted Media Extensions (DRM playback).</td></tr><tr><td><code>fullscreen</code></td><td>The Fullscreen API — see also the deprecated <code>allowfullscreen</code> below.</td></tr><tr><td><code>geolocation</code></td><td>The Geolocation API.</td></tr><tr><td><code>gyroscope</code></td><td>Gyroscope sensor data.</td></tr><tr><td><code>microphone</code></td><td>Microphone access.</td></tr><tr><td><code>payment</code></td><td>The Payment Request API.</td></tr><tr><td><code>picture-in-picture</code></td><td>Picture-in-Picture video.</td></tr><tr><td><code>publickey-credentials-get</code></td><td>WebAuthn credential retrieval.</td></tr><tr><td><code>screen-wake-lock</code></td><td>The Screen Wake Lock API.</td></tr><tr><td><code>web-share</code></td><td>The Web Share API.</td></tr><tr><td><code>xr-spatial-tracking</code></td><td>WebXR device tracking.</td></tr></tbody></table><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/video-embed.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;autoplay; picture-in-picture; fullscreen&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="allowfullscreen-legacy-boolean" tabindex="-1"><code>allowfullscreen</code> (legacy boolean) <a class="header-anchor" href="#allowfullscreen-legacy-boolean" aria-label="Permalink to &quot;`allowfullscreen` (legacy boolean)&quot;">​</a></h3><p>The older, single-purpose way to permit the Fullscreen API, predating the general <code>allow</code> Permissions Policy syntax. Still widely used (many third-party embed snippets — video players, maps — still emit it) and still functional, but <code>allow=&quot;fullscreen&quot;</code> is the modern equivalent and should be preferred in new code. Some embeds set both for maximum compatibility.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/video-embed.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> allowfullscreen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="allowpaymentrequest-deprecated" tabindex="-1"><code>allowpaymentrequest</code> (deprecated) <a class="header-anchor" href="#allowpaymentrequest-deprecated" aria-label="Permalink to &quot;`allowpaymentrequest` (deprecated)&quot;">​</a></h3><p>Formerly permitted the Payment Request API inside the frame. Removed from the HTML spec; use <code>allow=&quot;payment&quot;</code> instead.</p><hr><h2 id="sizing-layout" tabindex="-1">Sizing &amp; layout <a class="header-anchor" href="#sizing-layout" aria-label="Permalink to &quot;Sizing &amp; layout&quot;">​</a></h2><h3 id="width-height" tabindex="-1"><code>width</code> / <code>height</code> <a class="header-anchor" href="#width-height" aria-label="Permalink to &quot;`width` / `height`&quot;">​</a></h3><p>Presentational sizing attributes, in CSS pixels, applied as the initial rendered size. Prefer CSS (<code>width</code>/<code>height</code> or <code>iframeStyle</code> in this library&#39;s terms) for anything beyond a static default, since CSS takes precedence and is easier to make responsive.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/report.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;800&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;600&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="deprecated-sizing-layout-attributes" tabindex="-1">Deprecated sizing/layout attributes <a class="header-anchor" href="#deprecated-sizing-layout-attributes" aria-label="Permalink to &quot;Deprecated sizing/layout attributes&quot;">​</a></h3><p>These still parse without error in all current browsers but have no standardized effect and should not be used in new code — use CSS instead:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Replaced by</th></tr></thead><tbody><tr><td><code>frameborder</code></td><td>CSS <code>border</code> (default is now borderless in all modern browsers regardless of this attribute).</td></tr><tr><td><code>scrolling</code></td><td>CSS <code>overflow</code> on the iframe&#39;s contents.</td></tr><tr><td><code>marginwidth</code> / <code>marginheight</code></td><td>CSS <code>margin</code>/<code>padding</code> inside the framed document.</td></tr><tr><td><code>align</code></td><td>CSS <code>float</code>/<code>vertical-align</code>/flexbox/grid, depending on intent.</td></tr></tbody></table><hr><h2 id="loading-behavior" tabindex="-1">Loading behavior <a class="header-anchor" href="#loading-behavior" aria-label="Permalink to &quot;Loading behavior&quot;">​</a></h2><h3 id="loading" tabindex="-1"><code>loading</code> <a class="header-anchor" href="#loading" aria-label="Permalink to &quot;`loading`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>eager</code> (default)</td><td>Loads immediately, regardless of where it is in the viewport.</td></tr><tr><td><code>lazy</code></td><td>Defers loading until the iframe is near the viewport, the same mechanism as <code>&lt;img loading=&quot;lazy&quot;&gt;</code>.</td></tr></tbody></table><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/below-the-fold-widget.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> loading</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lazy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Useful for pages embedding several iframes (e.g. a dashboard of report previews) where only a few are visible at once.</p><hr><h2 id="naming-targeting" tabindex="-1">Naming &amp; targeting <a class="header-anchor" href="#naming-targeting" aria-label="Permalink to &quot;Naming &amp; targeting&quot;">​</a></h2><h3 id="name" tabindex="-1"><code>name</code> <a class="header-anchor" href="#name" aria-label="Permalink to &quot;`name`&quot;">​</a></h3><p>Assigns a browsing-context name, usable as a <code>target</code> for a <code>&lt;form&gt;</code>, <code>&lt;a&gt;</code>, or another iframe&#39;s navigation, and accessible from script as <code>window.frames[&#39;name&#39;]</code>. Rarely needed for the &quot;preview/render controlled content&quot; use case this library targets, but relevant if the embedded document contains links/forms that should open elsewhere in the frame tree.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preview-frame&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/report.html&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/other-report.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preview-frame&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Open other report here&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><h3 id="referrerpolicy" tabindex="-1"><code>referrerpolicy</code> <a class="header-anchor" href="#referrerpolicy" aria-label="Permalink to &quot;`referrerpolicy`&quot;">​</a></h3><p>Controls what <code>Referer</code> header (and <code>document.referrer</code> inside the frame) is sent when the iframe fetches its content.</p><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>no-referrer</code></td><td>Never send a referrer.</td></tr><tr><td><code>no-referrer-when-downgrade</code></td><td>Send referrer unless navigating from HTTPS to HTTP.</td></tr><tr><td><code>origin</code></td><td>Send only the origin (scheme+host+port), not the full URL.</td></tr><tr><td><code>origin-when-cross-origin</code></td><td>Full URL for same-origin, origin-only for cross-origin.</td></tr><tr><td><code>same-origin</code></td><td>Send referrer only for same-origin requests, none otherwise.</td></tr><tr><td><code>strict-origin</code></td><td>Origin only, and never on a downgrade.</td></tr><tr><td><code>strict-origin-when-cross-origin</code> (browser default)</td><td>Full URL same-origin, origin-only cross-origin, never on downgrade.</td></tr><tr><td><code>unsafe-url</code></td><td>Always send the full URL, including cross-origin and downgrades. Avoid — leaks path/query data broadly.</td></tr></tbody></table><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://third-party.example/widget&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> referrerpolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;no-referrer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><h3 id="title" tabindex="-1"><code>title</code> <a class="header-anchor" href="#title" aria-label="Permalink to &quot;`title`&quot;">​</a></h3><p>The single most important accessibility attribute on an iframe. Assistive technology announces it to describe what the embedded content <em>is</em>, since the iframe itself has no visible label the way a button or link would. There is no automatic fallback (the frame&#39;s own <code>&lt;title&gt;</code>, if it has one, is <strong>not</strong> used by all assistive technology consistently) — always set it explicitly on the <code>&lt;iframe&gt;</code> tag itself.</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/report.html&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Q3 financial report preview&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>See <a href="/accessibility">Accessibility</a> for how this library tests and documents the accessibility contract around this attribute.</p><hr><h2 id="non-standard-experimental" tabindex="-1">Non-standard / experimental <a class="header-anchor" href="#non-standard-experimental" aria-label="Permalink to &quot;Non-standard / experimental&quot;">​</a></h2><h3 id="csp" tabindex="-1"><code>csp</code> <a class="header-anchor" href="#csp" aria-label="Permalink to &quot;`csp`&quot;">​</a></h3><p>An experimental, Chromium-only attribute letting the embedding page assert a Content- Security-Policy that the framed document must already comply with (the framed document&#39;s own CSP, if any, still applies independently — this is an additional constraint imposed from outside, not a replacement). Not in the HTML Living Standard, not supported in Firefox/Safari as of this writing — treat as forward-looking, not something to depend on for real security boundaries today.</p><hr><h2 id="deprecated-obsolete-attributes" tabindex="-1">Deprecated / obsolete attributes <a class="header-anchor" href="#deprecated-obsolete-attributes" aria-label="Permalink to &quot;Deprecated / obsolete attributes&quot;">​</a></h2><p>Attributes that appear in older code/tutorials but should not be used:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Status</th></tr></thead><tbody><tr><td><code>align</code></td><td>Deprecated — use CSS.</td></tr><tr><td><code>frameborder</code></td><td>Deprecated — use CSS <code>border</code>.</td></tr><tr><td><code>longdesc</code></td><td>Deprecated — was meant to link to a long description; use ARIA or in-page text instead.</td></tr><tr><td><code>marginheight</code> / <code>marginwidth</code></td><td>Deprecated — use CSS.</td></tr><tr><td><code>scrolling</code></td><td>Deprecated — use CSS <code>overflow</code>.</td></tr><tr><td><code>seamless</code></td><td>Removed from the spec entirely (was briefly proposed, never widely implemented, then withdrawn).</td></tr><tr><td><code>allowpaymentrequest</code></td><td>Deprecated — use <code>allow=&quot;payment&quot;</code>.</td></tr></tbody></table><hr><h2 id="global-attributes-that-matter-in-practice" tabindex="-1">Global attributes that matter in practice <a class="header-anchor" href="#global-attributes-that-matter-in-practice" aria-label="Permalink to &quot;Global attributes that matter in practice&quot;">​</a></h2><p>Not iframe-specific, but routinely used alongside the attributes above:</p><ul><li><strong><code>id</code>, <code>class</code>, <code>style</code></strong> — standard targeting/styling hooks.</li><li><strong><code>tabindex</code></strong> — rarely needed; iframes are focusable by default when they contain focusable content.</li><li><strong><code>aria-*</code></strong> — <code>aria-label</code>/<code>aria-labelledby</code> can supplement or, in some implementations, substitute for <code>title</code>, but <code>title</code> remains the most universally supported mechanism and should be set regardless.</li><li><strong><code>data-*</code></strong> — arbitrary data attributes; this library uses its own <code>data-viw-id</code> attribute internally on <em>injected elements inside the iframe document</em> (not on the <code>&lt;iframe&gt;</code> tag itself) to track and replace assets by id.</li></ul><hr><h2 id="dom-properties-events-not-attributes-but-related" tabindex="-1">DOM properties &amp; events (not attributes, but related) <a class="header-anchor" href="#dom-properties-events-not-attributes-but-related" aria-label="Permalink to &quot;DOM properties &amp; events (not attributes, but related)&quot;">​</a></h2><p>These aren&#39;t HTML attributes — they&#39;re accessed from JavaScript — but are the other half of the platform surface this document is describing:</p><table tabindex="0"><thead><tr><th>Member</th><th>What it gives you</th></tr></thead><tbody><tr><td><code>iframe.contentWindow</code></td><td>The embedded browsing context&#39;s <code>Window</code>, if same-origin (or if sandboxed with <code>allow-same-origin</code>). Cross-origin access throws/returns a restricted proxy.</td></tr><tr><td><code>iframe.contentDocument</code></td><td>The embedded <code>Document</code>, same access rules as <code>contentWindow</code>. This is what <code>getSameOriginDocument()</code> in this library wraps with error handling.</td></tr><tr><td><code>load</code> event</td><td>Fires once the frame&#39;s document (and its sub-resources, same as a top-level page&#39;s <code>load</code> event) finishes loading. This is what <code>&lt;IframeWrapper /&gt;</code>&#39;s <code>load</code> event and auto-injection are built on.</td></tr><tr><td><code>window.postMessage()</code></td><td>The sanctioned way to communicate across a same-origin <strong>or cross-origin</strong> boundary without violating the same-origin policy — always specify a <code>targetOrigin</code>, never <code>&#39;*&#39;</code>, for anything containing meaningful data. Not currently wrapped by this library; tracked as a proposed feature in <a href="/feature-recommendations">Feature Recommendations</a> (<code>useIframeMessage</code>).</td></tr></tbody></table><hr><h2 id="full-attribute-table" tabindex="-1">Full attribute table <a class="header-anchor" href="#full-attribute-table" aria-label="Permalink to &quot;Full attribute table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Attribute</th><th>Category</th><th>Status</th></tr></thead><tbody><tr><td><code>src</code></td><td>Content</td><td>Standard</td></tr><tr><td><code>srcdoc</code></td><td>Content</td><td>Standard</td></tr><tr><td><code>sandbox</code></td><td>Security</td><td>Standard</td></tr><tr><td><code>allow</code></td><td>Permissions</td><td>Standard</td></tr><tr><td><code>allowfullscreen</code></td><td>Permissions</td><td>Legacy, still functional</td></tr><tr><td><code>allowpaymentrequest</code></td><td>Permissions</td><td>Deprecated</td></tr><tr><td><code>width</code></td><td>Sizing</td><td>Standard</td></tr><tr><td><code>height</code></td><td>Sizing</td><td>Standard</td></tr><tr><td><code>loading</code></td><td>Performance</td><td>Standard</td></tr><tr><td><code>name</code></td><td>Targeting</td><td>Standard</td></tr><tr><td><code>referrerpolicy</code></td><td>Privacy</td><td>Standard</td></tr><tr><td><code>title</code></td><td>Accessibility</td><td>Standard — treat as required</td></tr><tr><td><code>csp</code></td><td>Security (experimental)</td><td>Non-standard, Chromium-only</td></tr><tr><td><code>frameborder</code></td><td>Layout</td><td>Deprecated</td></tr><tr><td><code>scrolling</code></td><td>Layout</td><td>Deprecated</td></tr><tr><td><code>marginwidth</code> / <code>marginheight</code></td><td>Layout</td><td>Deprecated</td></tr><tr><td><code>align</code></td><td>Layout</td><td>Deprecated</td></tr><tr><td><code>longdesc</code></td><td>Accessibility</td><td>Deprecated</td></tr><tr><td><code>seamless</code></td><td>Layout</td><td>Removed from spec</td></tr></tbody></table><hr><h2 id="mapping-to-iframewrapper" tabindex="-1">Mapping to <code>&lt;IframeWrapper /&gt;</code> <a class="header-anchor" href="#mapping-to-iframewrapper" aria-label="Permalink to &quot;Mapping to `&lt;IframeWrapper /&gt;`&quot;">​</a></h2><p>How this library&#39;s component currently relates to the native attribute surface above — see <a href="/api/parameters">Parameters</a> for the full prop reference:</p><table tabindex="0"><thead><tr><th>Native attribute</th><th>Exposed today as</th><th>Notes</th></tr></thead><tbody><tr><td><code>src</code></td><td><code>src</code> prop</td><td>Direct passthrough.</td></tr><tr><td><code>srcdoc</code></td><td><code>srcdoc</code> prop</td><td>Direct passthrough.</td></tr><tr><td><code>sandbox</code></td><td><code>sandbox</code> prop</td><td>Defaults to <code>&quot;allow-scripts allow-same-origin&quot;</code> rather than being left unset.</td></tr><tr><td><code>title</code></td><td><code>title</code> prop</td><td>Not enforced as required at the type level; treated as required by convention and by the accessibility test suite.</td></tr><tr><td><code>class</code> / <code>style</code></td><td><code>iframeClass</code> / <code>iframeStyle</code> props</td><td>Named distinctly from a plain <code>class</code>/<code>style</code> binding to make clear they style the <em>frame</em>, not its contents.</td></tr><tr><td><code>allow</code></td><td><em>Not yet exposed</em></td><td>Proposed in <a href="/feature-recommendations">Feature Recommendations</a> #2.</td></tr><tr><td><code>referrerpolicy</code></td><td><em>Not yet exposed</em></td><td>Same proposal as above.</td></tr><tr><td><code>loading</code></td><td><em>Not yet exposed</em></td><td>Same proposal as above.</td></tr><tr><td><code>allowfullscreen</code></td><td><em>Not yet exposed</em></td><td>Same proposal as above.</td></tr><tr><td><code>name</code></td><td><em>Not yet exposed</em></td><td>No current proposal — low-demand for the preview/render use case this library targets; open an issue using the <a href="https://github.com/enterprise/vue-iframe-wrapper/issues/new?template=feature_request.md" target="_blank" rel="noreferrer">feature request template</a> if you need it.</td></tr><tr><td><code>width</code> / <code>height</code></td><td><em>Not exposed as discrete props</em></td><td>Use <code>iframeStyle</code>/<code>iframeClass</code> for sizing instead — see <a href="/guide/getting-started#sizing-the-iframe">Getting Started → Sizing the iframe</a>.</td></tr><tr><td>Everything under <a href="#deprecated--obsolete-attributes">Deprecated / obsolete</a></td><td><em>Intentionally not exposed</em></td><td>Not planned; these have no standardized effect in current browsers.</td></tr></tbody></table><p>Everything <strong>not</strong> in the left column of that table (the injection-related behavior — <code>css</code>, <code>cssUrls</code>, <code>js</code>, <code>jsUrls</code>, <code>autoInject</code>, <code>injectOnLoad</code>, <code>reloadKey</code>, and the exposed instance methods) is this library&#39;s own addition on top of the native element, not a passthrough of a native attribute — see <a href="/api/parameters">Parameters</a> for those.</p>',92)])])}const m=t(d,[["render",r]]);export{u as __pageData,m as default};
